 66 | /**
 67 |  * Estimate token count (rough approximation: 1 token ≈ 4 characters)
 68 |  */
 69 | function estimateTokens(text) {
 70 |   if (!text) return 0;
 71 |   return Math.ceil(text.length / 4);
 72 | }
 73 | 
 74 | /**
 75 |  * Truncate messages array to fit within token budget
 76 |  * Keeps most recent messages (they're most relevant)
 77 |  */
 78 | function truncateMessages(messages, maxTokens) {
 79 |   if (!messages || !Array.isArray(messages) || messages.length === 0) {
 80 |     return messages;
 81 |   }
 82 | 
 83 |   // Calculate total tokens in messages
 84 |   let totalTokens = 0;
 85 |   const withTokens = messages.map(msg => {
 86 |     const content = typeof msg.content === 'string' ? msg.content : JSON.stringify(msg.content);
 87 |     const tokens = estimateTokens(content);
 88 |     totalTokens += tokens;
 89 |     return { ...msg, _tokens: tokens };
 90 |   });
 91 | 
 92 |   // If within budget, return as-is
 93 |   if (totalTokens <= maxTokens) {
 94 |     return messages;
 95 |   }
 96 | 
 97 |   // Truncate from oldest messages, keeping most recent
 98 |   const truncated = [];
 99 |   let usedTokens = 0;
100 |   
101 |   for (let i = withTokens.length - 1; i >= 0; i--) {
102 |     if (usedTokens + withTokens[i]._tokens <= maxTokens) {
103 |       truncated.unshift(messages[i]);
104 |       usedTokens += withTokens[i]._tokens;
105 |     } else {
106 |       break;
107 |     }
108 |   }
109 | 
110 |   console.log(`[Orchestrator] ⚠️  Truncated ${messages.length - truncated.length} messages from history (${totalTokens} → ~${usedTokens} tokens, limit: ${maxTokens})`);
111 |   return truncated;
112 | }
