206 | class ConfidenceScorer {
207 |   constructor(performanceTracker) {
208 |     this.tracker = performanceTracker;
209 |     this.weights = {
210 |       recentSuccessRate: 0.35,
211 |       errorTypeRelevance: 0.25,
212 |       historicalPerformance: 0.20,
213 |       workload: 0.20
214 |     };
215 |   }
216 | 
217 |   calculateScore(agentId, errorType = null, taskType = null) {
218 |     const agent = this.tracker.getPerformanceStats(agentId);
219 |     if (!agent) return 0;
220 | 
221 |     // 1. Recent success rate (0-1)
222 |     const recentSuccessRate = this.tracker.getSuccessRate(agentId);
223 | 
224 |     // 2. Error type relevance (0-1)
225 |     let errorTypeRelevance = 0.8; // Default neutral
226 |     if (errorType && ERROR_AGENT_AFFINITY[errorType]) {
227 |       errorTypeRelevance = ERROR_AGENT_AFFINITY[errorType][agentId] || 0.8;
228 |     }
229 | 
230 |     // 3. Historical performance (0-1)
231 |     let historicalPerformance = 0.5;
232 |     if (taskType && agent.successByTaskType[taskType]) {
233 |       const taskStats = agent.successByTaskType[taskType];
234 |       historicalPerformance = taskStats.total > 0 
235 |         ? taskStats.success / taskStats.total 
236 |         : 0.5;
237 |     } else {
238 |       // Use overall success rate
239 |       historicalPerformance = agent.totalTasks > 0
240 |         ? agent.successfulTasks / agent.totalTasks
241 |         : 0.5;
242 |     }
243 | 
244 |     // 4. Workload factor (0-1) - lower workload = higher score
245 |     const maxWorkload = 10;
246 |     const workloadFactor = 1 - Math.min(agent.currentWorkload / maxWorkload, 1);
247 | 
248 |     // Calculate weighted score
249 |     const score = 
250 |       (recentSuccessRate * this.weights.recentSuccessRate) +
251 |       (errorTypeRelevance * this.weights.errorTypeRelevance) +
252 |       (historicalPerformance * this.weights.historicalPerformance) +
253 |       (workloadFactor * this.weights.workload);
254 | 
255 |     return Math.max(0, Math.min(1, score));
256 |   }
257 | 
258 |   rankAgents(availableAgents, errorType = null, taskType = null) {
259 |     const scores = [];
260 |     
261 |     for (const agentId of availableAgents) {
262 |       const score = this.calculateScore(agentId, errorType, taskType);
263 |       const stats = this.tracker.getPerformanceStats(agentId);
264 |       
265 |       scores.push({
266 |         agentId,
267 |         score: Math.round(score * 100) / 100,
268 |         details: {
269 |           successRate: this.tracker.getSuccessRate(agentId),
270 |           errorRelevance: errorType ? (ERROR_AGENT_AFFINITY[errorType]?.[agentId] || 0.8) : null,
271 |           historicalPerformance: stats?.totalTasks > 0 
272 |             ? stats.successfulTasks / stats.totalTasks 
273 |             : 0.5,
274 |           workload: stats?.currentWorkload || 0
275 |         }
276 |       });
277 |     }
278 | 
279 |     // Sort by score descending
280 |     scores.sort((a, b) => b.score - a.score);
281 |     return scores;
282 |   }
283 | }
