294 |     const { 
295 |       availableAgents = this.fallbackChain,
296 |       forceAgent = null,
297 |       errorType = null,
298 |       taskType = null
299 |     } = options;
300 | 
301 |     // Force specific agent if requested
302 |     if (forceAgent && availableAgents.includes(forceAgent)) {
303 |       return {
304 |         agent: forceAgent,
305 |         reason: 'forced',
306 |         confidence: 1.0,
307 |         isFallback: false
308 |       };
