315 |       return {
316 |         agent: 'local',
317 |         reason: 'default_fallback',
318 |         confidence: 0.3,
319 |         isFallback: true
320 |       };
321 |     }
322 | 
323 |     const selected = rankings[0];
324 |     const isFallback = rankings.length > 1 && 
325 |       availableAgents.indexOf(selected.agentId) > availableAgents.indexOf(this.fallbackChain[0]);
326 | 
327 |     return {
328 |       agent: selected.agentId,
329 |       reason: this.getReason(selected, taskType),
330 |       confidence: selected.score,
331 |       allRankings: rankings,
332 |       isFallback
