119 |   // Simple hash-based embedding for fallback
120 |   simpleEmbedding(text) {
121 |     const dim = 384;
122 |     const embedding = new Array(dim).fill(0);
123 |     for (let i = 0; i < text.length; i++) {
124 |       embedding[i % dim] += text.charCodeAt(i);
125 |     }
126 |     // Normalize
127 |     const norm = Math.sqrt(embedding.reduce((sum, v) => sum + v * v, 0));
128 |     return embedding.map(v => v / (norm || 1));
129 |   }
