131 |   cosineSimilarity(a, b) {
132 |     if (a.length !== b.length) return 0;
133 |     let dotProduct = 0, normA = 0, normB = 0;
134 |     for (let i = 0; i < a.length; i++) {
135 |       dotProduct += a[i] * b[i];
136 |       normA += a[i] * a[i];
137 |       normB += b[i] * b[i];
138 |     }
139 |     if (normA === 0 || normB === 0) return 0;
140 |     return dotProduct / (Math.sqrt(normA) * Math.sqrt(normB));
141 |   }
